const Web3 = require('web3');
const fs = require('fs');

// Set up web3 provider (e.g., Infura, Alchemy)
const provider = new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID');

// Create a new web3 instance with the provider
const web3 = new Web3(provider);

// Load private keys from file (securely store and load private keys)
const privateKeyFile = 'path/to/private/key.json';
const privateKeyJson = fs.readFileSync(privateKeyFile, 'utf8');
const privateKey = JSON.parse(privateKeyJson).private_key;

// Create a wallet instance with the loaded private key
const wallet = web3.eth.accounts.privateKeyToAccount(privateKey);

// Function to send ETH transaction
async function sendEthTransaction(to, amount) {
  try {
    const txCount = await web3.eth.getTransactionCount(wallet.address);
    const tx = {
      from: wallet.address,
      to,
      value: web3.utils.toWei(amount.toString(), 'ether'),
      gas: '20000',
      nonce: txCount,
    };
    const signedTx = await web3.eth.accounts.signTransaction(tx, privateKey);
    const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);
    console.log(`ETH sent to ${to} successfully!`);
  } catch (error) {
    console.error('Error sending ETH transaction:', error);
  }
}

// Function to interact with smart contract
async function interactWithContract(contractAddress, contractAbi, functionName, ...args) {
  try {
    const contract = new web3.eth.Contract(contractAbi, contractAddress);
    const txCount = await web3.eth.getTransactionCount(wallet.address);
    const tx = {
      from: wallet.address,
      to: contractAddress,
      gas: '20000',
      nonce: txCount,
    };
    const data = contract.methods[functionName](...args).encodeABI();
    const signedTx = await web3.eth.accounts.signTransaction({
      ...tx,
      data,
    }, privateKey);
    const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);
    console.log(`Contract interaction successful!`);
  } catch (error) {
    console.error('Error interacting with contract:', error);
  }
}

